export const SUPPORTED_COUNTRY_OPTIONS: EuropeCountryOption[] = [...EUROPE_COUNTRY_OPTIONS, CHINA_COUNTRY_OPTION];

function normalizeMatchValue(value: string) {
  return value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]/gu, "");
}

export function getEuropeCountryOptions() {
  return SUPPORTED_COUNTRY_OPTIONS;
}

export function getEuropeProvinceOptions(countryCode: string) {
  const code = (countryCode ?? "").toUpperCase();
  const country = getEuropeCountryOptions().find((item) => item.code === code);
  return country?.provinces ?? [];
}

export function getEuropeCityOptions(countryCode: string, provinceCode: string) {
  const province = getEuropeProvinceOptions(countryCode).find((item) => item.code === provinceCode);
  return province?.cities ?? [];
}

export function findEuropeCountryByCode(countryCode: string) {
  const code = (countryCode ?? "").toUpperCase();
  return getEuropeCountryOptions().find((item) => item.code === code) ?? null;
}

export function findBestProvinceCode(countryCode: string, provinceName: string) {
  const provinces = getEuropeProvinceOptions(countryCode);
  if (provinces.length === 0) return "";
  const normalized = normalizeMatchValue(provinceName ?? "");
  if (!normalized) return provinces[0].code;
  const exact = provinces.find((item) => normalizeMatchValue(item.name) === normalized);
  if (exact) return exact.code;
  const fuzzy = provinces.find(
    (item) =>
      normalizeMatchValue(item.name).includes(normalized) ||
      normalized.includes(normalizeMatchValue(item.name)),
  );
  return fuzzy?.code ?? provinces[0].code;
}

export function findBestCityName(countryCode: string, provinceCode: string, cityName: string) {
  const cities = getEuropeCityOptions(countryCode, provinceCode);
  if (cities.length === 0) return "";
  const normalized = normalizeMatchValue(cityName ?? "");
  if (!normalized) return cities[0];
  const exact = cities.find((item) => normalizeMatchValue(item) === normalized);
  if (exact) return exact;
  const fuzzy = cities.find(
    (item) =>
      normalizeMatchValue(item).includes(normalized) ||
      normalized.includes(normalizeMatchValue(item)),
  );
  return fuzzy ?? cities[0];
}

export function findBestProvinceAndCity(
  countryCode: string,
  provinceName: string,
  cityName: string,
): { provinceCode: string; cityName: string } {
  const provinces = getEuropeProvinceOptions(countryCode);
  if (provinces.length === 0) {
    return { provinceCode: "", cityName: "" };
  }

  const normalizedProvince = normalizeMatchValue(provinceName ?? "");
  const normalizedCity = normalizeMatchValue(cityName ?? "");

  if (normalizedCity) {
    const exactMatches: Array<{ provinceCode: string; cityName: string; provinceScore: number }> = [];
    for (const province of provinces) {
      const provinceNormalized = normalizeMatchValue(province.name);
      const provinceScore =
        normalizedProvince && provinceNormalized === normalizedProvince
          ? 3
          : normalizedProvince &&
              (provinceNormalized.includes(normalizedProvince) || normalizedProvince.includes(provinceNormalized))
            ? 1
            : 0;
      for (const item of province.cities) {
        if (normalizeMatchValue(item) === normalizedCity) {
          exactMatches.push({
            provinceCode: province.code,
            cityName: item,
            provinceScore,
          });
        }
      }
    }
    if (exactMatches.length > 0) {
      exactMatches.sort((a, b) => b.provinceScore - a.provinceScore);
      return {
        provinceCode: exactMatches[0].provinceCode,
        cityName: exactMatches[0].cityName,
      };
    }
  }

  const fallbackProvinceCode = findBestProvinceCode(countryCode, provinceName);
  const fallbackProvince = provinces.find((item) => item.code === fallbackProvinceCode) ?? null;
  const fallbackProvinceNormalized = normalizeMatchValue(fallbackProvince?.name ?? "");
  const provinceMatched =
    !normalizedProvince ||
    (fallbackProvinceNormalized.length > 0 &&
      (fallbackProvinceNormalized === normalizedProvince ||
        fallbackProvinceNormalized.includes(normalizedProvince) ||
        normalizedProvince.includes(fallbackProvinceNormalized)));
  const safeFallbackProvinceCode = provinceMatched ? fallbackProvinceCode : "";
  const fallbackCities = safeFallbackProvinceCode
    ? getEuropeCityOptions(countryCode, safeFallbackProvinceCode)
    : [];
  const fallbackCityExact = fallbackCities.find((item) => normalizeMatchValue(item) === normalizedCity) ?? "";
  return {
    provinceCode: safeFallbackProvinceCode,
    cityName: fallbackCityExact,
  };
}
